public record HttpRequest(
    String method, String url, Map<String, String> headers, String body
) {
    public static Builder builder(String method, String url) {
        return new Builder(method, url);
    }

    public static class Builder {
        private final String method;
        private final String url;
        private final Map<String, String> headers = new LinkedHashMap<>();
        private String body;

        private Builder(String method, String url) {
            this.method = Objects.requireNonNull(method);
            this.url = Objects.requireNonNull(url);
        }

        public Builder header(String key, String value) {
            headers.put(key, value); return this;
        }
        public Builder body(String body) { this.body = body; return this; }

        public HttpRequest build() {
            return new HttpRequest(method, url, Map.copyOf(headers), body);
        }
    }
}

from collections import deque

def topological_sort(num_nodes, edges):
    adj = [[] for _ in range(num_nodes)]
    in_degree = [0] * num_nodes

    for u, v in edges:
        adj[u].append(v)
        in_degree[v] += 1

    queue = deque(i for i in range(num_nodes) if in_degree[i] == 0)
    order = []

    while queue:
        node = queue.popleft()
        order.append(node)
        for neighbor in adj[node]:
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    if len(order) != num_nodes:
        raise ValueError('Graph has a cycle — topological sort impossible')

    return order

import { useState, useMemo } from 'react';

function usePagination({ totalItems, itemsPerPage = 10, initialPage = 1 }) {
  const [currentPage, setCurrentPage] = useState(initialPage);
  const totalPages = Math.ceil(totalItems / itemsPerPage);

  const pagination = useMemo(() => {
    const start = (currentPage - 1) * itemsPerPage;
    const end = Math.min(start + itemsPerPage, totalItems);
    return {
      startIndex: start,
      endIndex: end,
      currentPage,
      totalPages,
      hasPrev: currentPage > 1,
      hasNext: currentPage < totalPages,
    };
  }, [currentPage, totalItems, itemsPerPage, totalPages]);

  const goToPage = (page) => setCurrentPage(Math.max(1, Math.min(page, totalPages)));
  const nextPage = () => goToPage(currentPage + 1);
  const prevPage = () => goToPage(currentPage - 1);

  return { ...pagination, goToPage, nextPage, prevPage };
}

from functools import singledispatch, wraps

def methoddispatch(func):
    dispatcher = singledispatch(func)

    def wrapper(self, *args, **kwargs):
        # Dispatch on the type of the first argument after self
        if args:
            return dispatcher.dispatch(type(args[0]))(self, *args, **kwargs)
        return dispatcher(self, *args, **kwargs)

    wrapper.register = dispatcher.register
    wrapper.dispatch = dispatcher.dispatch
    wrapper.registry = dispatcher.registry
    return wrapper

