class Serializer:
    @methoddispatch
    def serialize(self, value):
        return str(value)

    @serialize.register(int)
    def _(self, value):
        return f'int:{value}'

    @serialize.register(list)
    def _(self, value):
        return f'list[{len(value)}]'

function withTimeout(asyncFn, timeoutMs, options = {}) {
  const controller = new AbortController();
  const { signal } = controller;

  const timeoutPromise = new Promise((_, reject) => {
    const timer = setTimeout(() => {
      controller.abort();
      reject(new DOMException(`Timed out after ${timeoutMs}ms`, 'TimeoutError'));
    }, timeoutMs);
    signal.addEventListener('abort', () => clearTimeout(timer));
  });

  const taskPromise = asyncFn(signal).catch(err => {
    if (signal.aborted && err.name !== 'TimeoutError') {
      throw new DOMException('Operation cancelled', 'AbortError');
    }
    throw err;
  });

  const result = Promise.race([taskPromise, timeoutPromise]);
  result.cancel = () => controller.abort();
  return result;
}

